python3 -c "
import sys,json,os,re
d=json.load(sys.stdin)
c=d.get('tool_input',{}).get('command','')
kws=sys.argv[1:]
def chk(t):
 for k in kws:
  if re.search(r'(?<![\w/.-])'+re.escape(k)+r'(?!\w)',t):return k
hit=chk(c)
if not hit:
 segs=re.split(r'[;&|]+',c)
 for seg in segs:
  ts=seg.split()
  if not ts:continue
  ex=[]
  if ts[0].endswith('.sh'):ex.append(ts[0])
  for i,t in enumerate(ts[:-1]):
   if t in('bash','sh','source','.') and ts[i+1].endswith('.sh'):ex.append(ts[i+1])
  for e in ex:
   p=e.strip(\"';\")
   if os.path.isfile(p):
    try:
     hit=chk(open(p).read())
     if hit:break
    except:pass
  if hit:break
if hit:
 json.dump({'hookSpecificOutput':{'hookEventName':'PreToolUse','permissionDecision':'ask','permissionDecisionReason':hit+' requires approval'}},sys.stdout)
" sudo
